function initWooapbCarousels(root=document){if(void 0===window.Swiper)return;const elements=root.querySelectorAll(".wooapb-carousel");elements.length&&elements.forEach(el=>{if("true"===el.dataset.swiperInit)return;const nextEl=el.querySelector(".swiper-button-next"),prevEl=el.querySelector(".swiper-button-prev"),paginationEl=el.querySelector(".swiper-pagination");let config={};try{config=el.dataset.swiper?JSON.parse(el.dataset.swiper):{}}catch(e){console.warn("Invalid swiper config",e)}new window.Swiper(el,{...config,navigation:!(!nextEl||!prevEl)&&{nextEl:nextEl,prevEl:prevEl},pagination:!!paginationEl&&{el:paginationEl,clickable:!0}}),el.dataset.swiperInit="true"})}document.addEventListener("DOMContentLoaded",()=>{initWooapbCarousels(document),console.log("test")});